// ═══════════════════════════════════════════════════════════
// Ajusta formato para Google Docs — Code Node (v4)
// doc_id vem do node "Criar Documento no Google Docs" ($json.id)
// summary vem do node "Sumarizador LLM" (Basic LLM Chain)
// transcription vem do node "Transcreve com Google Gemini"
// ═══════════════════════════════════════════════════════════

// ─── 1. Leitura de inputs (cada dado de seu node de origem) ───
const transcription = $('Transcreve com Google Gemini').first().json?.content?.parts?.[0]?.text || '';

// Basic LLM Chain output: pode estar em response.text, response, ou text
const chainOut = $input.first().json;
const summary = String(
  chainOut?.response?.text
  || chainOut?.response
  || chainOut?.text
  || chainOut?.output
  || ''
).trim();

// doc_id vem do node Google Docs (usa Drive API internamente, retorna campo "id")
const docId = String(
  $('Criar Documento no Google Docs').first().json?.id
  || $('Criar Documento no Google Docs').first().json?.documentId
  || ''
).trim();

// ─── 2. Validação (fail-fast com mensagem clara) ───
if (!docId) {
  const rawDocNode = JSON.stringify($('Criar Documento no Google Docs').first().json || {}).substring(0, 300);
  throw new Error('[meet2docs] doc_id ausente. Output do node Google Docs: ' + rawDocNode);
}
if (!summary) {
  const rawChain = JSON.stringify(chainOut || {}).substring(0, 300);
  throw new Error('[meet2docs] Resumo vazio. Output do Sumarizador: ' + rawChain);
}
if (!transcription) {
  // Nao bloqueia — grava so o resumo
}

// ─── 3. Monta documento: RESUMO primeiro, transcrição depois ───
const SUMMARY_HEADER       = '📋 RESUMO\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';
const TRANSCRIPTION_HEADER = '\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎙 TRANSCRIÇÃO COMPLETA\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';

const fullText = SUMMARY_HEADER
  + summary
  + TRANSCRIPTION_HEADER
  + (transcription || '(Transcricao nao disponivel)');

let text = fullText.replace(/\r\n/g, '\n');

// ─── 4. Parser de estilos (bold, italic, bullets) ───
let plainText = '';
const styles  = [];
const bullets = [];
let cursor = 1; // Google Docs startIndex comeca em 1

const lines = text.split('\n');

for (let line of lines) {
  // Linha vazia: apenas newline
  if (!line.trim()) {
    plainText += '\n';
    cursor++;
    continue;
  }

  const lineStartCursor = cursor;

  // Detecta bullets (✦, ✓ ou -)
  let isBullet = false;
  const trimmed = line.trim();
  if (trimmed.startsWith('✦') || trimmed.startsWith('✓') || trimmed.startsWith('-')) {
    isBullet = true;
    line = trimmed.substring(1).trim();
  }

  // Parse markdown bold/italic
  const regex = /(\*\*([^*]+)\*\*|\*([^*]+)\*|([^*]+))/g;
  let match;
  while ((match = regex.exec(line)) !== null) {
    const raw   = match[0];
    const clean = match[2] || match[3] || match[4] || '';
    if (!clean) continue;

    const start = cursor;
    const end   = cursor + clean.length;

    plainText += clean;

    if (raw.startsWith('**')) {
      styles.push({
        range: { startIndex: start, endIndex: end },
        textStyle: { bold: true },
        fields: 'bold'
      });
    } else if (raw.startsWith('*') && !raw.startsWith('**')) {
      styles.push({
        range: { startIndex: start, endIndex: end },
        textStyle: { italic: true },
        fields: 'italic'
      });
    }

    cursor = end;
  }

  plainText += '\n';
  cursor++;

  if (isBullet) {
    bullets.push({
      range: {
        startIndex: lineStartCursor,
        endIndex: cursor
      },
      bulletPreset: 'BULLET_DISC_CIRCLE_SQUARE'
    });
  }
}

// ─── 5. Monta array de requests para documents.batchUpdate ───
const requests = [];

// Insere texto
requests.push({
  insertText: {
    endOfSegmentLocation: {},
    text: plainText
  }
});

// Aplica estilos (bold/italic)
for (const s of styles) {
  requests.push({
    updateTextStyle: {
      range: s.range,
      textStyle: s.textStyle,
      fields: s.fields
    }
  });
}

// Aplica bullets
for (const b of bullets) {
  requests.push({
    createParagraphBullets: b
  });
}

// ─── 6. Retorna requests + doc_id ───
return [{ json: { requests, doc_id: docId } }];
